import httpx
from functools import wraps

def with_timeout_fallback(timeout_seconds: float, fallback_message: str):
    """Decorator: return a fallback string if the tool call times out."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except (httpx.TimeoutException, httpx.ConnectError) as exc:
                # Log for monitoring
                print(f"[WARN] Tool {func.__name__} timed out: {exc}")
                return fallback_message
        return wrapper
    return decorator

